*�����������������
 """
Extension classes enhance TouchDesigner component networks with python
functionality. An extension can be accessed via ext.ExtensionClassName from
any operator within the extended component. If the extension is "promoted", all
its attributes with capitalized names can be accessed directly through the
extended component, e.g. op('yourComp').ExtensionMethod()
"""

from collections import deque

class ConsoleExt:
	"""
	ConsoleExt description
	"""
	def __init__(self, ownerComp):
		# The component to which this extension is attached
		self.ownerComp = ownerComp
		self.replyDat = ownerComp.op('consoleText')
		self.prompt = ownerComp.op('prompt')
		self.entry = ownerComp.op('entry')
		self.sentLines = deque(maxlen=25)
		self.sentLineIndex = -1 # index into sentLines for arrow keys, -1 = curr
		self.currLine = '' # stored current line for arrow keys
		self.port = parent.TDAbleton.OSCIn.par.port.eval()

	def OnReply(self, args):
		if self.ownerComp.par.display.eval():
			self.prompt.par.enable = True
			if args[0]:
				self.prompt.panel.field = '...'
			else:
				self.prompt.panel.field = '>>>'
				for out in range(1,3):
					self.appendText(args[out])
				self.prompt.par.enable = False

	def appendText(self, text):
		for r in text.split('\n'):
			if r:
				while len(r) > 80:
					self.replyDat.text += r[:80] + '\n'
					# print(r[:80])
					r = r[80:]
				# print(r)
				self.replyDat.text += r + '\n'
				self.replyDat.scroll(1000000)
				#print(repr(r))

	def SendLine(self, line):
		self.sentLines.appendleft(line)
		self.sentLineIndex = -1
		parent.TDAbleton.SendOSC('/shell/consoleLine', [line])
		if self.ownerComp.par.display.eval():
			self.appendText(self.prompt.panel.field + ' ' + line)

	def OnKey(self, key):
		if key == 'up':
			if self.sentLineIndex == -1:
				self.currLine = self.entry.panel.fieldediting.val
			if self.sentLineIndex + 1 < len(self.sentLines):
				self.sentLineIndex += 1
				self.SetEntryText(self.sentLines[self.sentLineIndex])
		elif key == 'down':
			self.sentLineIndex -= 1
			if self.sentLineIndex == -1:
				self.SetEntryText(self.currLine)
			elif self.sentLineIndex == -2:
				self.sentLineIndex = -1
			else:
				self.SetEntryText(self.sentLines[self.sentLineIndex])
		elif key == 'tab':
			self.SetEntryText(self.entry.panel.fieldediting + '\t')

	def SetEntryText(self, text):
		self.prompt.setKeyboardFocus()
		self.entry.panel.field = text
		self.entry.setKeyboardFocus(selectAll=False)

	def Clear(self):
		self.replyDat.text = ''

	def onParPulse(self, par):
		if par.name == 'Clear':
			self.Clear()

